const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const leadId = String(body.lead_id || '').trim();
if (!leadId) return { json: { ok: false, status: 400, error: 'lead_id required' } };
const productsOverride = Array.isArray(body.products) ? body.products : null;
const roleOverride = String(body.role || '').trim() || null;
return { json: { token, leadId, productsOverride, roleOverride } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const inp = $('Extract Inputs').item.json;
return { json: { ok: true, leadId: inp.leadId, productsOverride: inp.productsOverride, roleOverride: inp.roleOverride } };

// Build the auth_users row from the lead. Parse the product list from
// the lead notes (the signup workflow wrote 'product=<x>' there) unless
// the caller passed an explicit products override.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const leads = allOf('Fetch Lead');
const lead = leads[0];
if (!lead) {
  return { json: { _failed: true, status: 404, error: 'Lead not found for that id' } };
}
if (!lead.email) {
  return { json: { _failed: true, status: 400, error: 'Lead has no email — cannot provision' } };
}

const inp = $('Check Admin').item.json;
let products = inp.productsOverride;
if (!products) {
  const notes = String(lead.notes || '');
  const m = notes.match(/product=([a-z_]+)/i);
  const product = m ? m[1].toLowerCase() : null;
  if (product && ['sales_engine','sentinel','ava','luxi','maxi','ciro','mga','smart_quote'].indexOf(product) !== -1) {
    products = [product];
  } else {
    products = [];
  }
}

// auth_users doesn't have a full_name column — the lead's full_name stays
// on the lead row only. Company name carries the lead's display identity
// for the dashboard topbar.
const row = {
  email:              String(lead.email).trim().toLowerCase(),
  user_role:          inp.roleOverride || 'client',
  company_name:       lead.company || lead.full_name || 'TBD',
  email_verified:     false,
  products:           products,
  onboarding_status:  'account_created',
  signup_source:      lead.source === 'saas_client_signup' ? 'demo_to_paid' : 'admin_provisioned'
};

return { json: { authUserRow: row, leadId: lead.id, leadEmail: lead.email, leadName: lead.full_name } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Upsert Auth User');
const authUser = rows[0];
const build = $('Build Auth User').item.json;
if (!authUser || !authUser.id) {
  const raw = $('Upsert Auth User').first().json || {};
  return { json: { ok: false, status: 500, error: 'Auth user upsert returned no row: ' + (raw.message || raw.error || 'unknown'), supabase_raw: raw } };
}
return { json: {
  ok: true,
  auth_user_id: authUser.id,
  email: authUser.email,
  user_role: authUser.user_role,
  full_name: authUser.full_name,
  products: authUser.products,
  onboarding_status: authUser.onboarding_status,
  lead_id: build.leadId,
  message: 'Provisioned ' + authUser.full_name + ' (' + authUser.email + ') with role ' + authUser.user_role + ' and products ' + JSON.stringify(authUser.products) + '. Send them a magic link via Supabase Auth -> Users -> Send Magic Link.'
} };
